#include<bits/stdc++.h>
using namespace std;
const int maxi=1e2+5;
int n,m,k;
string blocks[5],word;
bool flag[maxi];
int order[maxi];
bool ans;
void calc(int x){
	if(x==m+1){
		bool temp=true;
		for(int i=1;i<=m;i++){
			if(blocks[order[i]].find(word[i-1])==string::npos)
			temp=false;
		}
		ans=ans|temp;
		return ;
	}
	for(int i=1;i<=n;i++){
		if(flag[i])continue;
		order[x]=i;
		flag[i]=1;
		calc(x+1);
		flag[i]=0;
	}
}
int main()
{
	n=4;
	cin>>k;
	for(int i=1;i<=4;i++){
		cin>>blocks[i];
	}
	for(int i=0;i<k;i++){
		cin>>word;
		ans=false;
		m=word.length();
		calc(1);
		if(ans)cout<<"YES"<<endl;
		else cout<<"NO"<<endl;
	}
	return 0;
}
